   135	        ...(init.headers ?? {}),
   136	      },
   137	    },
   138	    AUTH_REQUEST_TIMEOUT_MS,
   139	  )
   140	
   141	  const payload = (await parseJsonSafe(response)) as ApiErrorPayload | T | null
   142	
   143	  if (!response.ok) {
   144	    const errorPayload = (payload as ApiErrorPayload) ?? null
   145	    throw new AuthApiError(extractErrorMessage(errorPayload), response.status, errorPayload)
   146	  }
   147	
   148	  return payload as T
